import os

app = Flask(__name__)

DB_CONFIG = {
    'host': os.environ.get('DB_HOST', 'localhost'),
    'port': os.environ.get('DB_PORT', '5432'),
    'database': os.environ.get('DB_NAME', 'analytics_db'),
    'user': os.environ.get('DB_USER', 'postgres'),
    'password': os.environ.get('DB_PASSWORD', 'password')
}

ALLOWED_TABLES = os.environ.get('ALLOWED_TABLES', 'users,orders,products,analytics').split(',')
MAX_LIMIT = int(os.environ.get('MAX_LIMIT', '1000'))

def get_db_connection():
    return psycopg2.connect(**DB_CONFIG)

def validate_identifier(identifier):
    if not re.match(r'^[a-zA-Z_][a-zA-Z0-9_]*$', identifier):
        raise ValueError(f"Invalid identifier: {identifier}")
    return identifier

def validate_table_name(table_name):
    validate_identifier(table_name)
    if table_name not in ALLOWED_TABLES:
        raise ValueError(f"Table '{table_name}' is not allowed")
    return table_name

def handle_errors(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        try:
            return f(*args, **kwargs)
        except ValueError as e:
            return jsonify({'error': str(e)}), 400
        except psycopg2.Error as e:
            return jsonify({'error': f'Database error: {str(e)}'}), 500
        except Exception as e:
            return jsonify({'error': f'Internal error: {str(e)}'}), 500
    return decorated_function

def build_where_clause(filters):
    if not filters:
        return sql.SQL(""), []
    
    conditions = []
    params = []
    
    for filter_item in filters:
        column = validate_identifier(filter_item.get('column'))
        operator = filter_item.get('operator', '=')
        value = filter_item.get('value')
        
        allowed_operators = {
            '=': sql.SQL('='),
            '!=': sql.SQL('!='),
            '>': sql.SQL('>'),
            '>=': sql.SQL('>='),
            '<': sql.SQL('<'),
            '<=': sql.SQL('<='),
            'LIKE': sql.SQL('LIKE'),
            'ILIKE': sql.SQL('ILIKE'),
            'IN': sql.SQL('IN'),
            'NOT IN': sql.SQL('NOT IN'),
            'IS NULL': sql.SQL('IS NULL'),
            'IS NOT NULL': sql.SQL('IS NOT NULL')
        }
        
        if operator not in allowed_operators:
            raise ValueError(f"Operator '{operator}' is not allowed")
        
        if operator in ['IS NULL', 'IS NOT NULL']:
            conditions.append(
                sql.SQL('{} {}').format(
                    sql.Identifier(column),
                    allowed_operators[operator]
                )
            )
        elif operator in ['IN', 'NOT IN']:
            if not isinstance(value, list):
                raise ValueError(f"Value for {operator} must be a list")
            placeholders = sql.SQL(', ').join([sql.Placeholder()] * len(value))
            conditions.append(
                sql.SQL('{} {} ({})').format(
                    sql.Identifier(column),
                    allowed_operators[operator],
                    placeholders
                )
            )
            params.extend(value)
        else:
            conditions.append(
                sql.SQL('{} {} {}').format(
                    sql.Identifier(column),
                    allowed_operators[operator],
                    sql.Placeholder()
                )
            )
            params.append(value)
    
    where_clause = sql.SQL(' WHERE ') + sql.SQL(' AND ').join(conditions)
    return where_clause, params

def build_order_clause(order_by):
    if not order_by:
        return sql.SQL("")
    
    order_parts = []
    for order_item in order_by:
        column = validate_identifier(order_item.get('column'))
        direction = order_item.get('direction', 'ASC').upper()
        
        if direction not in ['ASC', 'DESC']:
            raise ValueError(f"Invalid sort direction: {direction}")
        
        order_parts.append(
            sql.SQL('{} {}').format(
                sql.Identifier(column),
                sql.SQL(direction)
            )
        )
    
    return sql.SQL(' ORDER BY ') + sql.SQL(', ').join(order_parts)

def build_join_clause(joins):
    if not joins:
        return sql.SQL("")
    
    join_parts = []
    for join_item in joins:
        join_type = join_item.get('type', 'INNER').upper()
        join_table = validate_table_name(join_item.get('table'))
        on_condition = join_item.get('on')
        
        if join_type not in ['INNER', 'LEFT', 'RIGHT', 'FULL']:
            raise ValueError(f"Invalid join type: {join_type}")
        
        left_col = validate_identifier(on_condition.get('left'))
        right_col = validate_identifier(on_condition.get('right'))
        
        join_parts.append(
            sql.SQL(' {} JOIN {} ON {} = {}').format(
                sql.SQL(join_type),
                sql.Identifier(join_table),
                sql.Identifier(on_condition.get('left_table', join_table), left_col),
                sql.Identifier(on_condition.get('right_table'), right_col)
            )
        )
    
    return sql.SQL('').join(join_parts)

@app.route('/api/query', methods=['POST'])
@handle_errors
def dynamic_query():
    data = request.get_json()
    
    if not data:
        return jsonify({'error': 'Request body is required'}), 400
    
    table_name = validate_table_name(data.get('table'))
    columns = data.get('columns', ['*'])
    filters = data.get('filters', [])
    order_by = data.get('order_by', [])
    joins = data.get('joins', [])
    limit = min(int(data.get('limit', 100)), MAX_LIMIT)
    offset = int(data.get('offset', 0))
    
    if columns != ['*']:
        columns = [validate_identifier(col) for col in columns]
        select_clause = sql.SQL(', ').join([sql.Identifier(col) for col in columns])
    else:
        select_clause = sql.SQL('*')
    
    where_clause, params = build_where_clause(filters)
    order_clause = build_order_clause(order_by)
    join_clause = build_join_clause(joins)
    
    query = sql.SQL('SELECT {} FROM {}{}{}{}').format(
        select_clause,
        sql.Identifier(table_name),
        join_clause,
        where_clause,
        order_clause
    )
    
    query = query + sql.SQL(' LIMIT %s OFFSET %s')
    params.extend([limit, offset])
    
    conn = get_db_connection()
    try:
        with conn.cursor(cursor_factory=extras.RealDictCursor) as cur:
            cur.execute(query, params)
            results = cur.fetchall()
            
            count_query = sql.SQL('SELECT COUNT(*) FROM {}{}{}').format(
                sql.Identifier(table_name),
                join_clause,
                where_clause
            )
            cur.execute(count_query, params[:-2])
            total_count = cur.fetchone()['count']
            
            return jsonify({
                'data': results,
                'total': total_count,
                'limit': limit,
                'offset': offset
            })
    finally:
        conn.close()

@app.route('/api/aggregate', methods=['POST'])
@handle_errors
def aggregate_query():
    data = request.get_json()
    
    if not data:
        return jsonify({'error': 'Request body is required'}), 400
    
    table_name = validate_table_name(data.get('table'))
    aggregates = data.get('aggregates', [])
    group_by = data.get('group_by', [])
    filters = data.get('filters', [])
    having = data.get('having', [])
    
    if not aggregates:
        return jsonify({'error': 'At least one aggregate function is required'}), 400
    
    allowed_functions = ['COUNT', 'SUM', 'AVG', 'MIN', 'MAX']
    
    select_parts = []
    for agg in aggregates:
        func = agg.get('function', '').upper()
        column = agg.get('column', '*')
        alias = agg.get('alias')
        
        if func not in allowed_functions:
            raise ValueError(f"Function '{func}' is not allowed")
        
        if column != '*':
            column = validate_identifier(column)
            agg_expr = sql.SQL('{}({})').format(
                sql.SQL(func),
                sql.Identifier(column)
            )
        else:
            agg_expr = sql.SQL('{}(*)').format(sql.SQL(func))
        
        if alias:
            alias = validate_identifier(alias)
            agg_expr = sql.SQL('{} AS {}').format(agg_expr, sql.Identifier(alias))
        
        select_parts.append(agg_expr)
    
    if group_by:
        group_by_validated = [validate_identifier(col) for col in group_by]
        for col in group_by_validated:
            select_parts.insert(0, sql.Identifier(col))
        group_clause = sql.SQL(' GROUP BY ') + sql.SQL(', ').join(
            [sql.Identifier(col) for col in group_by_validated]
        )
    else:
        group_clause = sql.SQL('')
    
    where_clause, params = build_where_clause(filters)
    
    having_clause = sql.SQL('')
    if having and group_by:
        having_conditions = []
        for having_item in having:
            func = having_item.get('function', '').upper()
            column = validate_identifier(having_item.get('column'))
            operator = having_item.get('operator', '=')
            value = having_item.get('value')
            
            if func not in allowed_functions:
                raise ValueError(f"Function '{func}' is not allowed")
            
            allowed_operators = {'=': '=', '!=': '!=', '>': '>', '>=': '>=', '<': '<', '<=': '<='}
            if operator not in allowed_operators:
                raise ValueError(f"Operator '{operator}' is not allowed")
            
            having_conditions.append(
                sql.SQL('{}({}) {} {}').format(
                    sql.SQL(func),
                    sql.Identifier(column),
                    sql.SQL(operator),
                    sql.Placeholder()
                )
            )
            params.append(value)
        
        having_clause = sql.SQL(' HAVING ') + sql.SQL(' AND ').join(having_conditions)
    
    select_clause = sql.SQL(', ').join(select_parts)
    
    query = sql.SQL('SELECT {} FROM {}{}{}{}').format(
        select_clause,
        sql.Identifier(table_name),
        where_clause,
        group_clause,
        having_clause
    )
    
    conn = get_db_connection()
    try:
        with conn.cursor(cursor_factory=extras.RealDictCursor) as cur:
            cur.execute(query, params)
            results = cur.fetchall()
            
            return jsonify({
                'data': results,
                'count': len(results)
            })
    finally:
        conn.close()

