@app.route('/api/schema/<table_name>', methods=['GET'])
@handle_errors
def get_table_schema(table_name):
    table_name = validate_table_name(table_name)
    
    query = sql.SQL("""
        SELECT column_name, data_type, is_nullable, column_default
        FROM information_schema.columns
        WHERE table_name = %s
        ORDER BY ordinal_position
    """)
    
    conn = get_db_connection()
    try:
        with conn.cursor(cursor_factory=extras.RealDictCursor) as cur:
            cur.execute(query, [table_name])
            columns = cur.fetchall()
            
            return jsonify({
                'table': table_name,
                'columns': columns
            })
    finally:
        conn.close()

@app.route('/api/distinct', methods=['POST'])
@handle_errors
def get_distinct_values():
    data = request.get_json()
    
    if not data:
        return jsonify({'error': 'Request body is required'}), 400
    
    table_name = validate_table_name(data.get('table'))
    column = validate_identifier(data.get('column'))
    filters = data.get('filters', [])
    limit = min(int(data.get('limit', 100)), MAX_LIMIT)
    
    where_clause, params = build_where_clause(filters)
    
    query = sql.SQL('SELECT DISTINCT {} FROM {}{} ORDER BY {} LIMIT %s').format(
        sql.Identifier(column),
        sql.Identifier(table_name),
        where_clause,
        sql.Identifier(column)
    )
    params.append(limit)
    
    conn = get_db_connection()
    try:
        with conn.cursor(cursor_factory=extras.RealDictCursor) as cur:
            cur.execute(query, params)
            results = cur.fetchall()
            
            values = [row[column] for row in results]
            
            return jsonify({
                'column': column,
                'values': values,
                'count': len(values)
            })
    finally:
        conn.close()

